  "options": [
    {
      "text": "नए बकेट पब्लिक करें",
      "hint": "पहले न्यूनतम अधिकार का उपयोग करें।"
    },
    {
      "text": "S3 को ऑन-प्रीमिस ले जाएं और ACLs पर पूरी तरह नियंत्रण करें"
    },
    {
      "text": "डेटा को प्राइवेट ब्लॉकचेन में ले जाएं",
      "hint": "अजीबो-गरीब, ना?"
    },
    {
      "text": "न्यूनतम अधिकार सिद्धांत का उपयोग करें"
    },
    {
      "text": "नीति वाइल्डकार्ड्स का उपयोग करके आवश्यक पहुंच सुनिश्चित करें",
      "hint": "😯 नहीं!"
    }
  ],
  "questionProse": [
    "S3 बकेट अनुमतियों के लिए अनुशंसित दृष्टिकोण क्या है?"
  ],
  "explanationProse": [
    "लगभग सभी प्रणालियों में, \"न्यूनतम अधिकार\" डिज़ाइन को अपनाना सुरक्षा बढ़ाने और भविष्य में सुरक्षित रखने के लिए महत्वपूर्ण है। मौजूदा प्रणाली को बंद करने की कोशिश करना एक पूरे कार्यालय भवन को नए आधार पर स्थानांतरित करने के समान कठिन होता है।\n\n    S3 बकेट भी इसके अपवाह नहीं हैं। न्यूनतम अधिकार के सिद्धांत को लागू करने के लिए, कोई अनुमति न दें और केवल आवश्यक पहुंच दें। IAM भूमिकाओं और नीतियों का उपयोग अनुमति नियंत्रित करने के लिए करें और बकेट अनुमतियों की नियमित रूप से जांच करें।\n\n    सुरक्षा सर्वोत्तम प्रथाएँ:\n    - न्यूनतम अधिकार के सिद्धांत को लागू करें\n    - कोई अनुमति न दें\n    - केवल आवश्यक पहुंच दें\n    - IAM भूमिकाओं और नीतियों का उपयोग करें\n    - बकेट अनुमतियों की नियमित रूप से जांच करें\n\n    अत्यधिक अनुमति वाले सेटिंग्स से बचें जो संवेदनशील डेटा को खतरे में डाल सकते हैं।\n\n    [S3 सुरक्षा सर्वोत्तम प्रथाएँ](https://aws.amazon.com/s3/security/)"
  ]
}
